module RefModule(
	input wire clk,
	input wire set,
	input wire en,
	input wire [11:0] D,
	output reg [11:0] Q
);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge set or posedge dbg_halt) begin
	if (set)
		Q <= 12'b111111111111;
	else if (en)
		Q <= D;
end
endmodule
